// ✅ CORRECT — only 2 lines
const raw  = $input.first().json;
const body = raw.payload ? JSON.parse(raw.payload) : (raw.body || raw);

// ─── Safe sanitized accessor ──────────────────────────────
const safe = (v, fallback = '') => {
  if (v === null || v === undefined) return fallback;
  return String(v)
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, '')  // strip control chars
    .replace(/'/g, "\\'")                            // escape single quotes
    .trim() || fallback;
};

// ─── Support Slack interactive payload (button click) ────
const isSlackInteractive = !!raw.payload;
const slackPayload       = isSlackInteractive ? JSON.parse(raw.payload) : null;

// ─── Extract fields (supports 3 input formats) ────────────
// Format 1: Direct API call { signal_id, action, user_name, reason }
// Format 2: Slack slash command { text: "NCT123 ESCALATE reason here" }
// Format 3: Slack button interactive payload

let signalId, action, overrideBy, slackUserId, slackChannel, reason, newLevel, responseUrl;

if (isSlackInteractive && slackPayload) {
  // Slack button click
  const actionData  = slackPayload.actions?.[0] || {};
  const actionValue = actionData.value || '';
  const parts       = actionValue.split('|');  // format: "ESCALATE|NCT123|reason"

  action       = safe(parts[0] || '').toUpperCase();
  signalId     = safe(parts[1] || slackPayload.callback_id || '');
  reason       = safe(parts[2] || 'Triggered via Slack button');
  newLevel     = safe(parts[3] || '').toUpperCase();
  overrideBy   = safe(slackPayload.user?.name || slackPayload.user?.username || 'slack_user');
  slackUserId  = safe(slackPayload.user?.id || '');
  slackChannel = safe(slackPayload.channel?.name || slackPayload.channel?.id || '#oncowatch-alerts');
  responseUrl  = safe(slackPayload.response_url || '');

} else if (body.text && !body.action) {
  // Slack slash command: /override NCT123 ESCALATE reason here
  const parts  = String(body.text || '').trim().split(/\s+/);
  signalId     = safe(parts[0] || '');
  action       = safe(parts[1] || '').toUpperCase();
  newLevel     = action === 'RECLASSIFY' ? safe(parts[2] || '').toUpperCase() : '';
  reason       = action === 'RECLASSIFY'
    ? safe(parts.slice(3).join(' '))
    : safe(parts.slice(2).join(' ') || 'Via Slack slash command');
  overrideBy   = safe(body.user_name || body.user_id || 'slack_user');
  slackUserId  = safe(body.user_id || '');
  slackChannel = safe(body.channel_name || body.channel_id || '#oncowatch-alerts');
  responseUrl  = safe(body.response_url || '');

} else {
  // Direct API call
  signalId     = safe(body.signal_id || body.source_id);
  action       = safe(body.action || '').toUpperCase();
  overrideBy   = safe(body.user_name || body.user_id || body.analyst || 'api_user');
  slackUserId  = safe(body.user_id || '');
  slackChannel = safe(body.channel_id || body.channel || '#oncowatch-alerts');
  reason       = safe(body.reason || body.text || body.note || 'No reason provided');
  newLevel     = safe(body.new_level || body.level || '').toUpperCase();
  responseUrl  = safe(body.response_url || '');
}

// ─── Normalise channel name ───────────────────────────────
if (slackChannel && !slackChannel.startsWith('#') && !slackChannel.startsWith('C')) {
  slackChannel = `#${slackChannel}`;
}

// ─── Validation layer ─────────────────────────────────────
const errors = [];

if (!signalId)  errors.push('Missing signal_id / source_id');
if (!action)    errors.push('Missing action');
if (!overrideBy || overrideBy === 'api_user' && !body.user_name) {
  overrideBy = 'system';
}

const VALID_ACTIONS = ['APPROVE', 'ESCALATE', 'DISMISS', 'RECLASSIFY'];
if (action && !VALID_ACTIONS.includes(action)) {
  errors.push(`Invalid action: "${action}". Valid: ${VALID_ACTIONS.join(', ')}`);
}

const VALID_LEVELS = ['HIGH', 'MED', 'LOW'];
if (action === 'RECLASSIFY' && !VALID_LEVELS.includes(newLevel)) {
  errors.push(`RECLASSIFY requires new_level: HIGH, MED, or LOW. Got: "${newLevel}"`);
}

if (errors.length > 0) {
  throw new Error(`Override validation failed:\n${errors.map(e => `• ${e}`).join('\n')}`);
}

// ─── Priority map ─────────────────────────────────────────
const PRIORITY = { ESCALATE: 1, RECLASSIFY: 2, APPROVE: 3, DISMISS: 4 };

// ─── Action metadata ──────────────────────────────────────
const ACTION_META = {
  APPROVE:    { emoji: '✅', label: 'Approved',     color: '#36A64F', priority: PRIORITY.APPROVE   },
  ESCALATE:   { emoji: '🔴', label: 'Escalated',    color: '#FF0000', priority: PRIORITY.ESCALATE  },
  DISMISS:    { emoji: '🚫', label: 'Dismissed',    color: '#888888', priority: PRIORITY.DISMISS   },
  RECLASSIFY: { emoji: '🔄', label: 'Reclassified', color: '#FFB300', priority: PRIORITY.RECLASSIFY}
};

const meta = ACTION_META[action];

// ─── Build override fingerprint (for deduplication) ──────
const overrideId = `${signalId}_${action}_${Date.now()}`;

// ─── Urgency flag ─────────────────────────────────────────
const isUrgentAction = action === 'ESCALATE';

return [{
  json: {
    // Core override fields
    overrideId,
    signalId,
    action,
    overrideBy,
    slackUserId,
    slackChannel,
    reason,
    newLevel,
    responseUrl,

    // Action metadata
    actionEmoji:    meta.emoji,
    actionLabel:    meta.label,
    actionColor:    meta.color,
    actionPriority: meta.priority,
    isUrgentAction,

    // Source tracking
    inputFormat:    isSlackInteractive ? 'slack_button' : body.text && !body.action ? 'slack_slash' : 'direct_api',
    receivedAt:     new Date().toISOString(),
    requestId:      `OVR-${Date.now()}`
  }
}];

const override = $('Parse Override Request').first().json;
const signal   = $('Validate Signal').first().json;

// ─── Signal existence check ───────────────────────────────
if (!signal || !signal.source_id) {
  throw new Error(
    `[OncoWatch Override] Signal not found in database.\n` +
    `Signal ID: ${override.signalId}\n` +
    `Requested by: ${override.overrideBy}\n` +
    `Action: ${override.action}\n` +
    `Hint: Verify source_id exists in signals table.`
  );
}

// ─── Block double-override guard ──────────────────────────
const BLOCKED_REOVERRIDE = ['dismissed'];
if (BLOCKED_REOVERRIDE.includes(signal.override_status)) {
  throw new Error(
    `[OncoWatch Override] Signal ${override.signalId} is already "${signal.override_status}" ` +
    `and cannot be overridden again. Contact admin to reset.`
  );
}

// ─── Advanced scoring engine for RECLASSIFY ──────────────
const BASE_SCORES   = { HIGH: 7.0, MED: 4.0, LOW: 1.0 };
const COMPETITOR_BONUS = signal.competitor_flag ? 2.0 : 0;
const ESCALATE_FLOOR   = 8.5;  // escalated signals minimum score

function computeNewScore(action, newLevel, currentScore, isCompetitor) {
  const base = BASE_SCORES[newLevel] || parseFloat(currentScore) || 0;
  const competitorBonus = isCompetitor ? 2.0 : 0;

  switch (action) {
    case 'ESCALATE':
      // Always bring score to at least ESCALATE_FLOOR
      return Math.max(
        parseFloat(currentScore) + 1.5,
        ESCALATE_FLOOR
      );

    case 'RECLASSIFY':
      // Base + competitor bonus, capped at 10
      return Math.min(base + competitorBonus, 10.0);

    case 'APPROVE':
      // Slight score boost for approved signals
      return Math.min(parseFloat(currentScore) + 0.3, 10.0);

    case 'DISMISS':
      // Score zeroed out for dismissed signals
      return 0.0;

    default:
      return parseFloat(currentScore) || 0;
  }
}

const newScore = parseFloat(
  computeNewScore(
    override.action,
    override.newLevel,
    signal.impact_score,
    signal.competitor_flag
  ).toFixed(2)
);

// ─── Determine final impact level ────────────────────────
const finalLevel = (() => {
  if (override.action === 'RECLASSIFY') return override.newLevel;
  if (override.action === 'ESCALATE')   return 'HIGH';
  if (override.action === 'DISMISS')    return signal.impact_level; // preserve original
  return signal.impact_level;
})();

// ─── Urgency flag logic ───────────────────────────────────
const isUrgentAfterOverride = (
  override.action === 'ESCALATE' ||
  (finalLevel === 'HIGH' && signal.competitor_flag) ||
  newScore >= 8.5
);

// ─── Override status map ──────────────────────────────────
const OVERRIDE_STATUS_MAP = {
  APPROVE:    'approved',
  ESCALATE:   'escalated',
  DISMISS:    'dismissed',
  RECLASSIFY: 'reclassified'
};

// ─── Score delta display ──────────────────────────────────
const prevScore    = parseFloat(signal.impact_score) || 0;
const scoreDelta   = parseFloat((newScore - prevScore).toFixed(2));
const scoreDeltaStr = scoreDelta > 0
  ? `+${scoreDelta}`
  : String(scoreDelta);

// ─── Level change detection ───────────────────────────────
const levelChanged   = finalLevel !== signal.impact_level;
const levelChangeStr = levelChanged
  ? `${signal.impact_level} → ${finalLevel}`
  : `${signal.impact_level} (unchanged)`;

// ─── Score breakdown audit ────────────────────────────────
const overrideScoreBreakdown = JSON.stringify({
  action:           override.action,
  previousLevel:    signal.impact_level,
  finalLevel,
  previousScore:    prevScore,
  newScore,
  scoreDelta,
  competitorBonus:  COMPETITOR_BONUS,
  isUrgent:         isUrgentAfterOverride,
  overrideBy:       override.overrideBy,
  overrideId:       override.overrideId || `OVR-${Date.now()}`,
  scoringVersion:   1
});

// ─── Slack confirmation summary ───────────────────────────
const summaryLine =
  `${override.actionEmoji} *${override.actionLabel}* by ${override.overrideBy} ` +
  `| ${signal.key_drug || signal.drug_name} (${signal.key_indication}) ` +
  `| Score: ${prevScore} → ${newScore} (${scoreDeltaStr}) ` +
  `| Level: ${levelChangeStr}`;

return [{
  json: {
    // ── Override metadata ──────────────────────────────
    ...override,
    overrideStatus:        OVERRIDE_STATUS_MAP[override.action],
    isUrgentAfterOverride,
    overrideScoreBreakdown,

    // ── Signal original data ───────────────────────────
    drug:            signal.key_drug || signal.drug_name   || 'Unknown',
    indication:      signal.key_indication                 || 'Unknown',
    sponsor:         signal.sponsor                        || 'Unknown',
    signalType:      signal.signal_type                    || 'unknown',
    isCompetitor:    signal.competitor_flag                || false,
    aiSummary:       signal.ai_summary                     || 'No summary',
    url:             signal.url                            || '',
    previousLevel:   signal.impact_level,
    previousScore:   prevScore,
    currentOverride: signal.override_status               || 'none',

    // ── Computed fields ────────────────────────────────
    finalLevel,
    newScore,
    scoreDelta,
    scoreDeltaStr,
    levelChanged,
    levelChangeStr,
    summaryLine,

    // ── Timestamps ────────────────────────────────────
    processedAt: new Date().toISOString()
  }
}];
